mod.globalevent:
domodlib('CTF_config') domodlib('CTF_lib')
local daysOpen = {}
for k, v in pairs(ctfConfig.days) do table.insert(daysOpen, k) end
function onThink(interval) if isInArray(daysOpen, os.date('%A')) then if isInArray(ctfConfig.days[os.date('%A')], os.date('%X', os.time())) then if getStorage(ctfConfig.eventStorage) ~= 1 then doStartCountingCtfEvent(0) doSetStorage(ctfConfig.eventStorage, 1) end end end
if getStorage(ctfConfig.eventStorage) == 1 then checkDeathRoomCTF()
for _, playerWithFlag in ipairs(getPlayersOnline()) do if getCreatureStorage(playerWithFlag, ctfConfig.flag.storage) == 1 then doSendAnimatedText(getThingPos(playerWithFlag), 'FLAG', COLOR_DARKYELLOW) break end end end return true end
